import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Limiting the input length to prevent buffer overflow
        if (userInput.length() > 10) {
            System.out.println("Input string is too long. Please enter a string with at most 10 characters.");
            return;
        }

        char[] buffer = new char[10];
        userInput.getChars(0, Math.min(userInput.length(), buffer.length), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
